    cow:      { EN: 'I have a best friend and feel sad when we are apart!', FR: "J'ai une meilleure amie et je m'ennuie quand elle n'est pas là !", HU: 'Legjobb barátom van, és szomorkodok, ha nincs mellettem!', DE: 'Ich habe eine beste Freundin und werde traurig, wenn wir getrennt sind!', ES: '¡Tengo una mejor amiga y me pongo triste cuando estamos separadas!', PT: 'Tenho uma melhor amiga e fico triste quando estamos separadas!', IT: 'Ho una migliore amica e mi rattristisco quando siamo separate!', NL: 'Ik heb een beste vriendin en word verdrietig als we gescheiden zijn!', DA: 'Jeg har en bedste ven og bliver ked af det, når vi er adskilt!', SV: 'Jag har en bästa vän och blir ledsen när vi separeras!', NB: 'Jeg har en bestevenn og blir lei meg når vi skilles!', IS: 'Ég á besta vin og verð sár þegar við erum aðskilin!', GA: 'Tá cara is fearr agam agus bíonn brón orm nuair a bhímid scartha!' },
    fox:      { EN: 'I can climb trees even better than cats!', FR: 'Je grimpe aux arbres encore mieux que les chats !', HU: 'Jobban mászok fára, mint a macskák!', DE: 'Ich klettere sogar besser auf Bäume als Katzen!', ES: '¡Puedo subir a los árboles incluso mejor que los gatos!', PT: 'Consigo subir às árvores ainda melhor do que os gatos!', IT: 'Riesco a salire sugli alberi ancora meglio dei gatti!', NL: 'Ik kan zelfs beter in bomen klimmen dan katten!', DA: 'Jeg kan klatre op i træer endnu bedre end katte!', SV: 'Jag kan klättra i träd ännu bättre än katter!', NB: 'Jeg kan klatre i trær enda bedre enn katter!', IS: 'Ég klíf tré jafnvel betur en kettir!', GA: 'Is féidir liom crainn a dhreapadh fiú níos fearr ná cait!' },
    wolf:     { EN: 'I live and hunt in a close family pack!', FR: 'Je vis et chasse en famille très soudée !', HU: 'Szoros csapatban élek és vadászom a családommal!', DE: 'Ich lebe und jage im engen Familienrudel!', ES: '¡Vivo y cazo en una manada familiar unida!', PT: 'Vivo e caço numa matilha familiar próxima!', IT: 'Vivo e caccio in un branco familiare unito!', NL: 'Ik leef en jaag in een hecht familieroedel!', DA: 'Jeg lever og jager i en nær familieflock!', SV: 'Jag lever och jagar i en nära familjeflcok!', NB: 'Jeg lever og jakter i en nær familieflokk!', IS: 'Ég lifi og veiði í náinni fjölskylduhjörð!', GA: 'Maireann mé agus déanaim seilg i ngrúpa teaghlaigh dlúth!' },
    squirrel: { EN: 'I bury nuts for a snack later — then forget exactly where!', FR: "J'enterre des noix pour plus tard... et j'oublie où !", HU: 'Elások diót uzsonnára — aztán elfelejtem, hol!', DE: 'Ich vergrabe Nüsse für später — und vergesse dann genau, wo!', ES: '¡Entierro nueces para después — y olvido exactamente dónde!', PT: 'Enterra nozes para depois — e esquece exatamente onde!', IT: 'Seppellisco ghiande per dopo — e poi dimentico esattamente dove!', NL: 'Ik begraaf noten voor later — en vergeet dan precies waar!', DA: 'Jeg gemmer nødder til senere — og glemmer præcis, hvor!', SV: 'Jag gräver ner nötter för senare — och glömmer sedan exakt var!', NB: 'Jeg graver ned nøtter til senere — og glemmer så nøyaktig hvor!', IS: 'Ég fel hnetur til síðar — og gleymi síðan nákvæmlega hvar!', GA: 'Adhlacaim cnónna le haghaidh níos déanaí — agus dearmadaim go díreach cá bhfuil siad!' },
    pig:      { EN: 'I can sniff out food buried underground with my sensitive nose!', FR: 'Mon groin ultra-sensible trouve de la nourriture cachée sous terre !', HU: 'Érzékeny orrommal megtalálom a föld alá rejtett ételt!', DE: 'Meine empfindliche Schnauze findet Essen, das unter der Erde vergraben ist!', ES: '¡Mi sensible hocico puede encontrar comida enterrada bajo tierra!', PT: 'O meu focinho sensível consegue encontrar comida enterrada no chão!', IT: 'Il mio naso sensibile trova il cibo sepolto sottoterra!', NL: 'Mijn gevoelige snuit vindt eten dat onder de grond is begraven!', DA: 'Min sensitive snude kan finde mad begravet under jorden!', SV: 'Min känsliga nos kan hitta mat begravd under marken!', NB: 'Min sensitive snute kan finne mat gravd ned under jorda!', IS: 'Næmt nef mitt getur fundið mat grafinn undir jörðu!', GA: 'Is féidir le mo shrón íogair bia atá curtha faoin talamh a aimsiú!' },
    sheep:    { EN: 'I remember 50 faces — sheep or human — for over 2 years!', FR: "Je me souviens de 50 visages pendant plus de 2 ans — je n'oublie jamais mes amis !", HU: '50 arcot emlékezek 2 évig — barátaim sosem esnek ki a fejemből!', DE: 'Ich merke mir 50 Gesichter — Schafe oder Menschen — über 2 Jahre lang!', ES: '¡Recuerdo 50 caras — de oveja o humano — durante más de 2 años!', PT: 'Lembro 50 caras — de ovelha ou humano — durante mais de 2 anos!', IT: 'Ricordo 50 facce — di pecora o umana — per oltre 2 anni!', NL: 'Ik onthoud 50 gezichten — schaap of mens — voor meer dan 2 jaar!', DA: 'Jeg husker 50 ansigter — får eller mennesker — i over 2 år!', SV: 'Jag minns 50 ansikten — får eller människor — i över 2 år!', NB: 'Jeg husker 50 ansikter — sau eller menneske — i over 2 år!', IS: 'Ég man eftir 50 andlitum — kind eða mannlegt — í yfir 2 ár!', GA: 'Cuimhním ar 50 aghaidh — caora nó duine — ar feadh níos mó ná 2 bhliain!' },
    rooster:  { EN: 'I crow every single morning to wake my friends!', FR: 'Je chante chaque matin pour réveiller mes amis !', HU: 'Minden reggel kukorékólok, hogy felébresszem barátaimat!', DE: 'Ich krähe jeden Morgen, um meine Freunde zu wecken!', ES: '¡Canto cada mañana para despertar a mis amigos!', PT: 'Canto todas as manhãs para acordar os meus amigos!', IT: 'Canto ogni mattina per svegliare i miei amici!', NL: 'Ik kraai elke ochtend om mijn vrienden wakker te maken!', DA: 'Jeg galer hver morgen for at vække mine venner!', SV: 'Jag gal varje morgon för att väcka mina vänner!', NB: 'Jeg galer hver morgen for å vekke vennene mine!', IS: 'Ég krák á hverjum morgni til að vekja vini mína!', GA: 'Déanaim glaoch gach maidin le mo chairde a dhúiseacht!' },
